# LeetCode 通常会预定义 ListNode
# class ListNode:
#     def __init__(self, val=0, next=None):
#         self.val = val
#         self.next = next

class Solution:
    def gameResult(self, head):
        front = []   # 包含数字 2，最终移动到队首
        middle = []  # 既不淘汰，也不移动
        back = []    # 包含数字 3，最终移动到队尾

        cur = head
        while cur:
            x = cur.val

            # 非法数字，直接返回 -1
            if x < 0 or x > 1000000000:
                return "-1"

            # 规则 1：3 的倍数直接淘汰
            if x % 3 == 0:
                cur = cur.next
                continue

            s = str(x)

            # 规则 2 优先于规则 3
            if '3' in s:
                back.append(str(x))
            elif '2' in s:
                front.append(str(x))
            else:
                middle.append(str(x))

            cur = cur.next

        ans = front + middle + back

        # 没有剩余参与者时返回 -1
        if not ans:
            return "-1"

        return " ".join(ans)
```

```java
import java.util.*;

class Solution {
    public String gameResult(ListNode head) {
        List<String> front = new ArrayList<>();   // 包含数字 2，最终移动到队首
        List<String> middle = new ArrayList<>();  // 既不淘汰，也不移动
        List<String> back = new ArrayList<>();    // 包含数字 3，最终移动到队尾

        ListNode cur = head;

        while (cur != null) {
            long x = cur.val; // ListNode.val 是 long，不能用 int 接收

            // 非法数字，直接返回 -1
            if (x < 0 || x > 1000000000L) {
                return "-1";
            }

            // 规则 1：3 的倍数直接淘汰
            if (x % 3 == 0) {
                cur = cur.next;
                continue;
            }

            // 规则 2 优先于规则 3
            if (containsDigit(x, 3)) {
                back.add(String.valueOf(x));
            } else if (containsDigit(x, 2)) {
                front.add(String.valueOf(x));
            } else {
                middle.add(String.valueOf(x));
            }

            cur = cur.next;
        }

        List<String> ans = new ArrayList<>();

        // 最终顺序：移到队首组 + 保持不变组 + 移到队尾组
        ans.addAll(front);
        ans.addAll(middle);
        ans.addAll(back);

        // 如果全部被淘汰，返回 -1
        if (ans.isEmpty()) {
            return "-1";
        }

        return String.join(" ", ans);
    }

    // 判断数字 x 的十进制表示中是否包含 digit
    private boolean containsDigit(long x, int digit) {
        if (x == 0) {
            return digit == 0;
        }

        while (x > 0) {
            if (x % 10 == digit) {
                return true;
            }
            x /= 10;
        }

        return false;
    }
}
