#include <string>
#include <vector>
using namespace std;

// LeetCode 通常会预定义 ListNode
// struct ListNode {
//     int val;
//     ListNode *next;
//     ListNode(int x) : val(x), next(nullptr) {}
// };

class Solution {
public:
    string gameResult(ListNode* head) {
        vector<string> front;   // 包含数字 2，最终移动到队首
        vector<string> middle;  // 既不淘汰，也不移动
        vector<string> back;    // 包含数字 3，最终移动到队尾

        ListNode* cur = head;

        while (cur != nullptr) {
            long long x = cur->val;

            // 非法数字，直接返回 -1
            if (x < 0 || x > 1000000000LL) {
                return "-1";
            }

            // 规则 1：3 的倍数直接淘汰
            if (x % 3 == 0) {
                cur = cur->next;
                continue;
            }

            // 规则 2 优先于规则 3
            if (containsDigit(x, 3)) {
                back.push_back(to_string(x));
            } else if (containsDigit(x, 2)) {
                front.push_back(to_string(x));
            } else {
                middle.push_back(to_string(x));
            }

            cur = cur->next;
        }

        vector<string> ans;

        // 按照最终顺序拼接：队首移动组 + 不变组 + 队尾移动组
        for (string s : front) ans.push_back(s);
        for (string s : middle) ans.push_back(s);
        for (string s : back) ans.push_back(s);

        // 没有剩余参与者时返回 -1
        if (ans.empty()) {
            return "-1";
        }

        string res = ans[0];
        for (int i = 1; i < ans.size(); i++) {
            res += " " + ans[i];
        }

        return res;
    }

private:
    // 判断数字 x 的十进制表示中是否包含 digit
    bool containsDigit(long long x, int digit) {
        if (x == 0) {
            return digit == 0;
        }

        while (x > 0) {
            if (x % 10 == digit) {
                return true;
            }
            x /= 10;
        }

        return false;
    }
};
