var gameResult = function(head) {
    var front = [];   // 包含数字 2，最终移动到队首
    var middle = [];  // 既不淘汰，也不移动
    var back = [];    // 包含数字 3，最终移动到队尾

    var cur = head;
    while (cur) {
        var x = cur.val;
        // 非法数字，直接返回 -1
