        if (x % 3 === 0) {
            cur = cur.next;
            continue;
        }
        var s = String(x);
        if (s.indexOf('3') !== -1) {
            back.push(s);
        } else if (s.indexOf('2') !== -1) {
            front.push(s);
        } else {
            middle.push(s);
        }
        cur = cur.next;
    }

    var ans = front.concat(middle, back);
    if (ans.length === 0) return "-1";
    return ans.join(' ');
};
